{
  "claims": [
    {
      "claim_text": "AB 2602 requires informed consent by performers in the film, music, and other entertainment sectors if studios wish to utilize their digital replicas created through AI technology."
    },
    {
      "claim_text": "Digital replica is defined as a computer-generated, highly realistic electronic representation that is identifiable as the voice or visual likeness of an individual."
    },
    {
      "claim_text": "Some contracts in the entertainment industry include clauses that grant full use of a performer’s voice and likeness forever."
    },
    {
      "claim_text": "Non-union performers and voice actors, particularly in video games, are especially vulnerable to exploitation regarding their digital replicas."
    },
    {
      "claim_text": "AB 2602 ensures that performers provide informed consent and are represented by a lawyer or union representative before transferring rights to their digital replicas."
    },
    {
      "claim_text": "AB 2602 strengthens a working performer’s fundamental right to control their voice and likeness and consent to how it’s used."
    },
    {
      "claim_text": "The legislation is presented as a model for how AI regulation should occur across all industries."
    }
  ]
}
